import React, { useState, useCallback } from 'react';

const allowedExtensions = [
  '.stl', '.obj', '.wrl', '.step', '.stp', '.iges', '.igs', '.3mf', '.dxf', '.dwg', '.zip',
];

// Utility function to check file extension
function isAllowedFile(fileName) {
  const lowerName = fileName.toLowerCase();
  return allowedExtensions.some(ext => lowerName.endsWith(ext));
}

function App() {
  const [dragActive, setDragActive] = useState(false);
  const [uploadedFiles, setUploadedFiles] = useState([]);
  const [menuOpen, setMenuOpen] = useState(false);
  const [accountMenuOpen, setAccountMenuOpen] = useState(false);
  const [languageMenuOpen, setLanguageMenuOpen] = useState(false);

  const handleDragOver = useCallback((e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(true);
  }, []);

  const handleDragLeave = useCallback((e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
  }, []);

  const handleDrop = useCallback((e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    const files = e.dataTransfer.files;
    handleFiles(files);
  }, []);

  const handleFiles = (files) => {
    const validFiles = [];
    for (let i = 0; i < files.length; i++) {
      if (isAllowedFile(files[i].name) && files[i].size <= 400 * 1024 * 1024) {
        validFiles.push(files[i]);
      }
    }
    if (validFiles.length > 0) {
      setUploadedFiles(validFiles);
      // TODO: Implement upload to backend if desired
    } else {
      alert('No valid files uploaded. Allowed types: ' + allowedExtensions.join(', '));
    }
  };

  const onFileChange = (e) => {
    const files = e.target.files;
    handleFiles(files);
  };

  return (
    <>
      <header className="header">
        <div className="header-left">
          <div className="logo" aria-label="Voodoo Manufacturing logo">VOODOO<br/><span className="manufacturing-text">MANUFACTURING</span></div>
        </div>
        <nav className="header-nav desktop-nav">
          <ul>
            <li className="nav-item language-select" onClick={() => setLanguageMenuOpen(!languageMenuOpen)} tabIndex={0} aria-haspopup="true" aria-expanded={languageMenuOpen} >
              <span><span className="material-icons">language</span> English <span className="material-icons arrow-down">expand_more</span></span>
              {languageMenuOpen && (
                <ul className="dropdown-menu">
                  <li>English</li>
                  <li>Spanish</li>
                  <li>French</li>
                </ul>
              )}
            </li>
            <li className="nav-item"><span className="material-icons">help_outline</span> How it works</li>
            <li className="nav-item quote-button"><button>Get a new quote</button></li>
            <li className="nav-item account-select" onClick={() => setAccountMenuOpen(!accountMenuOpen)} tabIndex={0} aria-haspopup="true" aria-expanded={accountMenuOpen}>
              <span><span className="material-icons">settings</span> My account <span className="material-icons arrow-down">expand_more</span></span>
              {accountMenuOpen && (
                <ul className="dropdown-menu">
                  <li>Profile</li>
                  <li>Settings</li>
                  <li>Log out</li>
                </ul>
              )}
            </li>
          </ul>
        </nav>
        <button 
          className="hamburger-button mobile-only" 
          aria-label="Menu"
          aria-expanded={menuOpen}
          aria-controls="mobile-menu"
          onClick={() => setMenuOpen(!menuOpen)}
        >
          <span className="material-icons">menu</span>
        </button>
        {menuOpen && (
          <nav className="mobile-nav mobile-only" id="mobile-menu" role="menu">
            <ul>
              <li role="menuitem">How it works</li>
              <li role="menuitem"><button className="quote-button">Get a new quote</button></li>
              <li role="menuitem">My account</li>
              <li role="menuitem">Language</li>
            </ul>
          </nav>
        )}
      </header>

      <main className="main-content">
        <section 
          className={`upload-area${dragActive ? ' drag-active' : ''}`} 
          onDragOver={handleDragOver} 
          onDragLeave={handleDragLeave} 
          onDrop={handleDrop}
          tabIndex={0}
          aria-label="Drag and drop files here"
        >
          <div className="upload-icon-wrapper" aria-hidden="true">
            <span className="material-icons upload-icon">folder_open</span>
          </div>
          <div className="upload-text-wrapper">
            <p><strong>Drag and drop files here</strong></p>
            <p className="supported-files">
              .stl, .obj, .wrl, .step (.stp), .iges (.igs), .3mf, .dxf, .dwg and .zip (with models and textures) files <br/>
              up to 400 Mb
            </p>
            <label htmlFor="fileInput" className="browse-button" tabIndex={0} role="button" aria-label="Browse files to upload">BROWSE FILES</label>
            <input 
              type="file" 
              id="fileInput" 
              multiple 
              onChange={onFileChange} 
              style={{ display: 'none' }} 
              accept={allowedExtensions.join(',')}
            />
          </div>
        </section>
        {uploadedFiles.length > 0 && (
          <section className="uploaded-files">
            <h2>Files ready for upload:</h2>
            <ul>
              {uploadedFiles.map((file, idx) => (
                <li key={idx}>{file.name} ({(file.size / 1024 / 1024).toFixed(2)} MB)</li>
              ))}
            </ul>
          </section>
        )}
        <p className="upload-note" aria-live="polite">
          <span className="material-icons lock-icon" aria-hidden="true">lock</span> Instant quoting tool secures all uploaded files, protecting your intellectual property
        </p>
      </main>

      <footer className="footer">
        <div className="footer-left">
          <div className="footer-logo" aria-label="Voodoo Manufacturing logo">VOODOO</div>
          <p className="footer-powered">
            Powered by 3D Printing Tech<br />
            Copyright © 2020
          </p>
        </div>
        <div className="footer-right">
          <a href="mailto:contact@voodoomfg.com" className="footer-contact" aria-label="Contact email">contact@voodoomfg.com</a>
        </div>
      </footer>

